  88→    img_buffer = await sharp(file.buffer)
  89→    .webp({quality: 80})
  90→    .toBuffer();
  91→
  92→    const folderName = `user_id_${userId}`;
  93→    const fileName = `${Date.now()}_${crypto.randomUUID()}.webp`;
  94→    const filePath = `${folderName}/${fileName}`;
  95→
  96→    const {data: uploadImage, error: errorUploadImage} = await supabase.storage
