 180→router.get('/getFollowsData', async(req, res) => {
 181→    const {userId, loggedInUserId} = req.query;
 182→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 183→    // console.log(req.query)
 184→    try {
 185→        const followersCountPromise = supabase
 186→        .from('follows')
 187→        .select('*', {count: 'exact', head: true})
 188→        .eq('following_id', userId);
 189→
 190→        const followingCountPromise = supabase
 191→        .from('follows')
 192→        .select('*', {count: 'exact', head: true})
 193→        .eq('follower_id', userId)
 194→
 195→        const isFollowingPromise = supabase
 196→        .from('follows')
 197→        .select('*', {count: 'exact', head: true})
 198→        .eq('follower_id', loggedInUserId)
 199→        .eq('following_id', userId)
 200→
 201→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 202→            followersCountPromise, followingCountPromise, isFollowingPromise,
 203→        ])
 204→
 205→
 206→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 207→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 208→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 209→
 210→        if(errorFollowers || errorFollowings || errorIsfollowing){
 211→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 212→            return res.status(500).json({error: 'failed to fetch data'})
 213→        }
 214→
 215→        return res.status(200).json({
 216→            followersCount: followersCount,
 217→            followingsCount: followingsCount,
 218→            isFollowing: isFollowingCount > 0
 219→        })
 220→
 221→    } catch (error) {
 222→        console.error('Error in Promise.all:', error);
 223→        res.status(500).json({ error: 'An unexpected error occurred' });
 224→    }
 225→
 226→})
