 385→        *,
 386→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count)),
 387→        users!sender_id(name, user_email, image_url, id, badge)
 388→        `)
 389→    .eq('receiver_id', receiverId)
 390→    .eq('read', false)
 391→    .order('created_at', {ascending: false})
 392→    .order('id', {ascending: false})
 393→    .limit(fetchLimit)
 394→
 395→    let opinionQuery = supabase
