 397→    .select(`
 398→        *,
 399→        opinions!opinion_id(id, opinion, user_id, created_at),
 400→        users!sender_id(name, user_email, image_url, id, badge)
 401→        `)
 402→    .eq('receiver_id', receiverId)
 403→    .eq('read', false)
 404→    .order('created_at', {ascending: false})
 405→    .order('id', {ascending: false})
 406→    .limit(fetchLimit)
 407→
 408→    if(before){
 409→        journalQuery = journalQuery.lt('created_at', before);
 410→        opinionQuery = opinionQuery.lt('created_at', before);
 411→    }
 412→
 413→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
