 417→        return res.status(500).json({error: 'supabase error while getting unread notification'})
 418→    }
 419→    if(opinionResult.error){
 420→        console.error('supabase error:', opinionResult.error.message);
 421→        return res.status(500).json({error: 'supabase error while getting unread opinion notification'})
 422→    }
 423→
 424→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 425→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 426→
 427→    const merged = [...journalNotifs, ...opinionNotifs]
 428→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 429→
 430→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 431→
 432→    let hasLikedResult = [];
 433→    let hasBookMarkedResult = [];
 434→    if(journalIds.length > 0){
 435→        const [hasLiked, hasBookMarked] = await Promise.all([
 436→            supabase.from('likes').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds),
 437→            supabase.from('bookmarks').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds)
