 439→
 440→        if(hasLiked.error || hasBookMarked.error){
 441→            console.error('error', hasLiked.error || hasBookMarked.error)
 442→            return res.status(500).json({error: 'supabase error on likes or bookmarks table'})
 443→        }
 444→        hasLikedResult = hasLiked.data || [];
