416→        if(typeof content === 'string' && content.trim()){
417→            resolvedContent = content;
418→        }
419→
420→        if(!resolvedContent){
421→            console.error('text content is missing for text post update');
422→            throw {status: 400, error: 'text content is missing for text post update'};
423→        }
424→
425→        const parseData = parseTextContentSafely(resolvedContent);
426→        if(!parseData){
427→            console.error('failed to parse text content for update');
428→            throw {status: 400, error: 'failed to parse text content for update'};
429→        }
430→
431→        resolvedCanvasDoc = null;
432→        embeddingBody = parseData.wholeText || '';
433→    }
434→
435→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
436→
437→    const embeddingResult = embeddings;
438→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
439→        console.error('failed to generate embeddings')
440→        throw {status: 400, error: 'failed to generate embeddings'};
441→    }
442→
443→    const journalData = {
444→        content: resolvedContent,
445→        title: resolvedTitle,
446→        post_type: resolvedPostType,
447→        canvas_doc: resolvedCanvasDoc,
448→        embeddings: embeddings
449→    }
450→
451→    const {data, error} = await supabase
452→    .from('journals')
453→    .update(journalData)
454→    .eq('id', journalId)
455→    .eq('user_id', userId)
456→
457→    if(error){
458→        console.error('supabase error while uploading content:', error.message);
459→        throw{status: 500, error: 'supabase error while uploading content'};
460→    }
461→
462→    return true;
463→}
