 269→const parseMediaTimestamp = (item = {}) => {
 270→    const fileName = item?.name || '';
 271→    const timestampPrefix = fileName.match(/^(\d+)_/);
 272→
 273→    if(timestampPrefix?.[1]){
 274→        const parsedPrefix = Number(timestampPrefix[1]);
 275→        if(!Number.isNaN(parsedPrefix)){
 276→            return parsedPrefix;
 277→        }
 278→    }
 279→
 280→    const parsedDate = Date.parse(item?.created_at || item?.updated_at || '');
 281→    return Number.isNaN(parsedDate) ? 0 : parsedDate;
 282→};
