 284→const createInitialMediaCursorState = () => ({
 285→    offsets: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, 0])),
 286→    exhausted: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, false])),
 287→    pending: []
 288→});
 289→
 290→const parseMediaCursor = (cursor) => {
 291→    if(!cursor){
 292→        return createInitialMediaCursorState();
 293→    }
 294→
 295→    try {
 296→        const decoded = Buffer.from(cursor, 'base64').toString('utf8');
 297→        const parsed = JSON.parse(decoded);
 298→        const initial = createInitialMediaCursorState();
 299→
 300→        if(parsed?.offsets && typeof parsed.offsets === 'object'){
 301→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
 302→                const value = Number(parsed.offsets[bucket]);
 303→                initial.offsets[bucket] = Number.isNaN(value) || value < 0 ? 0 : value;
 304→            });
 305→        }
 306→
 307→        if(parsed?.exhausted && typeof parsed.exhausted === 'object'){
 308→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
 309→                initial.exhausted[bucket] = Boolean(parsed.exhausted[bucket]);
 310→            });
 311→        }
 312→
 313→        if(Array.isArray(parsed?.pending)){
 314→            initial.pending = parsed.pending
 315→                .filter((item) => PROFILE_MEDIA_BUCKETS.includes(item?.bucket) && typeof item?.path === 'string' && typeof item?.name === 'string')
 316→                .map((item) => ({
 317→                    bucket: item.bucket,
 318→                    path: item.path,
 319→                    name: item.name,
 320→                    createdAt: item.createdAt || null,
 321→                    timestamp: Number(item.timestamp) || 0
 322→                }));
 323→        }
 324→
 325→        return initial;
 326→    } catch {
 327→        return createInitialMediaCursorState();
 328→    }
 329→};
