 381→        .from(bucket)
 382→        .createSignedUrl(path, 60 * 60);
 383→
 384→    if(!signedUrlError && signedUrlData?.signedUrl){
 385→        return signedUrlData.signedUrl;
 386→    }
 387→
 388→    const {data: publicUrlData} = supabase.storage
 389→        .from(bucket)
 390→        .getPublicUrl(path);
 391→
 392→    return publicUrlData?.publicUrl || null;
 393→};
