 761→    const comments = journal?.comment_count?.[0]?.count || 0;
 762→    const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 763→    const views = journal?.views || 0;
 764→    return (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
